import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const TYPE_CONFIG = {
  request_accepted: { icon:'✅', color:'#4ade80', label:'Application Accepted',  link: (n) => `/projects/${n.relatedId}` },
  request_rejected: { icon:'❌', color:'#ff5757', label:'Application Rejected',  link: (n) => `/projects/${n.relatedId}` },
  new_request:      { icon:'📬', color:'#ffb347', label:'New Application',       link: (n) => `/projects/${n.relatedId}` },
  project_closed:   { icon:'🔴', color:'#ff5757', label:'Project Closed',        link: (n) => `/projects/${n.relatedId}` },
  friend_request:   { icon:'🤝', color:'#6c63ff', label:'Connection Request',    link: () => '/friends' },
  message:          { icon:'💬', color:'#00d4aa', label:'New Message',           link: () => '/messages' },
  announcement:     { icon:'📢', color:'#ffb347', label:'New Announcement',      link: () => '/announcements' },
  general:          { icon:'🔔', color:'#9aa3bf', label:'Notification',          link: () => '/dashboard' },
};

export default function Notifications() {
  const { API } = useAuth();
  const navigate = useNavigate();
  const [notifications, setNotifications] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [filter, setFilter]     = useState('all');

  const h = () => ({ headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }, timeout: 15000 });

  const load = async () => {
    setLoading(true);
    try {
      const { data } = await axios.get(`${API}/notifications`, h());
      setNotifications(data);
    } catch {}
    setLoading(false);
  };

  useEffect(() => { load(); }, [API]);

  const markRead = async (id) => {
    try {
      await axios.put(`${API}/notifications/${id}/read`, {}, h());
      setNotifications(prev=>prev.map(n=>n._id===id?{...n,read:true}:n));
    } catch {}
  };

  const markAllRead = async () => {
    try {
      await axios.put(`${API}/notifications/read-all`, {}, h());
      setNotifications(prev=>prev.map(n=>({...n,read:true})));
    } catch {}
  };

  const handleClick = (n) => {
    markRead(n._id);
    const cfg = TYPE_CONFIG[n.type] || TYPE_CONFIG.general;
    navigate(cfg.link(n));
  };

  const unread = notifications.filter(n=>!n.read);
  const filtered = filter==='unread' ? unread : notifications;

  const formatTime = (date) => {
    const d = new Date(date);
    const now = new Date();
    const diff = Math.floor((now-d)/1000);
    if (diff < 60) return 'just now';
    if (diff < 3600) return `${Math.floor(diff/60)}m ago`;
    if (diff < 86400) return `${Math.floor(diff/3600)}h ago`;
    return d.toLocaleDateString('en-IN',{day:'numeric',month:'short'});
  };

  return (
    <div style={{padding:'2rem',maxWidth:700,margin:'0 auto'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'2rem'}}>
        <div>
          <h1 style={{fontWeight:800,fontSize:'1.75rem',marginBottom:'0.25rem'}}>🔔 Notifications</h1>
          <p style={{color:'#9aa3bf',fontSize:'0.875rem'}}>{unread.length > 0 ? `${unread.length} unread` : 'All caught up!'}</p>
        </div>
        <div style={{display:'flex',gap:'0.75rem'}}>
          {unread.length > 0 && <button onClick={markAllRead} style={{padding:'8px 16px',borderRadius:8,border:'1px solid #6c63ff40',background:'rgba(108,99,255,0.1)',color:'#6c63ff',fontSize:'0.8rem',fontWeight:600,cursor:'pointer'}}>✓ Mark all read</button>}
          <button onClick={load} style={{padding:'8px 14px',borderRadius:8,border:'1px solid #252d47',background:'transparent',color:'#9aa3bf',fontSize:'0.8rem',cursor:'pointer'}}>🔄</button>
        </div>
      </div>

      {/* Filter */}
      <div style={{display:'flex',gap:'0.5rem',marginBottom:'1.5rem'}}>
        <button onClick={()=>setFilter('all')} style={{padding:'6px 16px',borderRadius:8,border:`1px solid ${filter==='all'?'#6c63ff':'#252d47'}`,background:filter==='all'?'rgba(108,99,255,0.15)':'transparent',color:filter==='all'?'#6c63ff':'#9aa3bf',fontWeight:600,cursor:'pointer',fontSize:'0.8rem'}}>All ({notifications.length})</button>
        <button onClick={()=>setFilter('unread')} style={{padding:'6px 16px',borderRadius:8,border:`1px solid ${filter==='unread'?'#ff6b9d':'#252d47'}`,background:filter==='unread'?'rgba(255,107,157,0.1)':'transparent',color:filter==='unread'?'#ff6b9d':'#9aa3bf',fontWeight:600,cursor:'pointer',fontSize:'0.8rem'}}>
          Unread {unread.length > 0 && <span style={{background:'#ff6b9d',color:'#fff',borderRadius:99,padding:'1px 5px',fontSize:'0.65rem',marginLeft:'4px'}}>{unread.length}</span>}
        </button>
      </div>

      {loading ? (
        <div style={{textAlign:'center',padding:'4rem',color:'#6c63ff'}}>Loading notifications...</div>
      ) : filtered.length === 0 ? (
        <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:16,padding:'4rem',textAlign:'center',color:'#5c6580'}}>
          <div style={{fontSize:'3rem',marginBottom:'1rem'}}>🔔</div>
          <div style={{color:'#9aa3bf'}}>{filter==='unread'?'No unread notifications':'No notifications yet'}</div>
          <div style={{fontSize:'0.875rem',marginTop:'0.5rem'}}>You'll get notified when someone accepts your request, sends a message, or posts an announcement!</div>
        </div>
      ) : (
        <div style={{display:'flex',flexDirection:'column',gap:'0.5rem'}}>
          {filtered.map(n => {
            const cfg = TYPE_CONFIG[n.type] || TYPE_CONFIG.general;
            return (
              <div
                key={n._id}
                onClick={() => handleClick(n)}
                style={{background:n.read?'#161c2e':'rgba(108,99,255,0.05)',border:`1px solid ${n.read?'#252d47':'#6c63ff30'}`,borderRadius:12,padding:'1rem',cursor:'pointer',display:'flex',gap:'1rem',alignItems:'flex-start',transition:'border-color 0.2s'}}
                onMouseEnter={e=>e.currentTarget.style.borderColor='#6c63ff40'}
                onMouseLeave={e=>e.currentTarget.style.borderColor=n.read?'#252d47':'#6c63ff30'}
              >
                <div style={{width:42,height:42,borderRadius:12,background:`${cfg.color}15`,border:`1px solid ${cfg.color}30`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:'1.2rem',flexShrink:0}}>{cfg.icon}</div>
                <div style={{flex:1}}>
                  <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',gap:'0.5rem'}}>
                    <div>
                      <div style={{fontWeight:n.read?500:700,fontSize:'0.9rem',color:'#e8eaf0',marginBottom:'0.2rem'}}>{n.message || cfg.label}</div>
                      <div style={{color:cfg.color,fontSize:'0.75rem',fontWeight:600}}>{cfg.label}</div>
                    </div>
                    <div style={{display:'flex',flexDirection:'column',alignItems:'flex-end',gap:'0.25rem',flexShrink:0}}>
                      <span style={{color:'#5c6580',fontSize:'0.7rem'}}>{formatTime(n.createdAt)}</span>
                      {!n.read && <div style={{width:8,height:8,borderRadius:'50%',background:'#6c63ff'}} />}
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
